import json

# Get cases and accounts data from stored variables
cases = var_functions.query_db_48
accounts = var_functions.query_db_44

from datetime import datetime
from collections import defaultdict

# Build account state map
state_map = {}
for acc in accounts:
    aid = acc['Id']
    state = acc['ShippingState']
    if aid and state:
        state_map[aid] = state
        if aid.startswith('#'):
            state_map[aid[1:]] = state

# Calculate closure times by state
state_times = defaultdict(list)
start = datetime(2021, 4, 1)
end = datetime(2022, 10, 26)

for case in cases:
    try:
        created = datetime.fromisoformat(case['createddate'].replace('Z', '+00:00'))
        closed = datetime.fromisoformat(case['closeddate'].replace('Z', '+00:00'))
        if created < start or created > end:
            continue
        hours = (closed - created).total_seconds() / 3600
        aid = case['accountid'] or ''
        if aid.startswith('#'):
            aid = aid[1:]
        state = state_map.get(aid, None)
        if state:
            state_times[state].append(hours)
    except:
        pass

# Find state with 3+ cases and lowest average
best_state = None
best_avg = float('inf')

for state, times in state_times.items():
    if len(times) >= 3:
        avg = sum(times) / len(times)
        if avg < best_avg:
            best_avg = avg
            best_state = state

result = best_state if best_state else "NO_STATE"
print("__RESULT__:")
print(json.dumps(result))

